ValidationScript.Source:
            import sailpoint.object.Filter;
       import sailpoint.object.QueryOptions;
       import sailpoint.object.Identity;
       Identity identity = null;
       if (null != value) {
           Filter filter = Filter.ignoreCase(Filter.and(Filter.eq("samAccountName", value), Filter.or(Filter.eq("type", "contractor"), Filter.eq("type", "non-hr contractor"))));
           //Identity identity=context.getUniqueObject(Identity.class,filter);
           QueryOptions qo = new QueryOptions();
           qo.addFilter(filter);
           List identities = context.getObjects(Identity.class, qo);
           if (identities.size() == 0) {
               return value + ": IIQ Username not found! Please contact Service Desk";
           } else if (identities.size() > 1) {
               return value + ": Multiple Network IDs found! Please contact Service Desk";
           } else if (identities.size() == 1) {
               identity = identities.get(0);
			   String idType = identity.getAttribute("type") != null ? identity.getAttribute("type").toString():null;
               if (!identity.isInactive() @and idType != null @and idType.equalsIgnoreCase("non-hr contractor")) {
                   return value + ": is 'ACTIVE', an active user can not be enabled!";
               }else if(idType != null @and identity.isInactive() @and idType.equalsIgnoreCase("contractor")){
					return value + ": is a Inactive 'CONTRACTOR' user, this user's Identity is not eligible for enablement";
			   } else if (idType != null @and !identity.getAttribute("type").toLowerCase().contains("contractor")) {
                   return value + ": IIQ User must be contractor or non-hr Contractor";
               }else if(idType == null) {
                   return value + ": Cannot determine IIQ User Type,Please contact Service Desk!";
               }
			   form.getField("cwrusername").setValue(identity.getName());
           }
       }
